internal final class ETGGrainReceiptNumSeq extends NumberSeqApplicationModule
{
}

Method.Source:
protected void loadModule()
{
    NumberSeqDatatype datatype = NumberSeqDatatype::construct();

    datatype.parmDatatypeId(extendedTypeNum(ETGGrainReceiptNoteId));
    datatype.parmReferenceHelp(literalStr("Grain receipt number"));
    datatype.parmReferenceLabel(literalStr("Grain receipt number"));
    datatype.parmWizardIsContinuous(true);
    datatype.parmWizardIsManual(NoYes::No);
    datatype.parmWizardFetchAheadQty(10);
    datatype.parmSortField(1);

    datatype.addParameterType(NumberSeqParameterType::DataArea, true, false);

    this.create(datatype);
}

[SubscribesTo(classstr(NumberSeqGlobal),
    delegatestr(NumberSeqGlobal, buildModulesMapDelegate))]
static void buildModulesMapSubscriber(Map numberSeqModuleNamesMap)
{
    NumberSeqGlobal::addModuleToMap(
        classnum(ETGGrainReceiptNumSeq),
        numberSeqModuleNamesMap);
}
